1: import { useState, useRef, useEffect } from "react";
2: import { Link, useNavigate } from "react-router";
3: import { ChevronLeft, ChevronRight, Bell, Settings, LogOut, User } from "lucide-react";
4: import { motion, AnimatePresence } from "motion/react";
5: import { useAuth } from "../../contexts/AuthContext";
6: 
7: export function AppRightSidebar() {
8:   const { profile, signOut } = useAuth();
9:   const navigate = useNavigate();
10:   const [dropdownOpen, setDropdownOpen] = useState(false);
11:   const dropdownRef = useRef<HTMLDivElement>(null);
12: 
13:   // Dynamic Calendar State
14:   const [calendarDate, setCalendarDate] = useState(new Date());
15:   const year = calendarDate.getFullYear();
16:   const month = calendarDate.getMonth();
17: 
18:   const monthNames = [
19:     "January", "February", "March", "April", "May", "June",
20:     "July", "August", "September", "October", "November", "December"
21:   ];
22: 
23:   const daysOfWeek = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];
24: 
25:   const getDaysInMonth = (y: number, m: number) => new Date(y, m + 1, 0).getDate();
26:   
27:   const getFirstDayOfMonth = (y: number, m: number) => {
28:     const day = new Date(y, m, 1).getDay();
29:     return day === 0 ? 6 : day - 1; // Adjust so Monday is 0
30:   };
31: 
32:   const daysInMonth = getDaysInMonth(year, month);
33:   const firstDayIndex = getFirstDayOfMonth(year, month);
34: 
35:   // Generate blank spaces and days
36:   const calendarCells = [];
37:   for (let i = 0; i < firstDayIndex; i++) {
38:     calendarCells.push(null);
39:   }
40:   for (let i = 1; i <= daysInMonth; i++) {
41:     calendarCells.push(i);
42:   }
43: 
44:   const handlePrevMonth = () => {
45:     setCalendarDate(new Date(year, month - 1, 1));
46:   };
47: 
48:   const handleNextMonth = () => {
49:     setCalendarDate(new Date(year, month + 1, 1));
50:   };
51: 
52:   const handleLogout = async () => {
53:     setDropdownOpen(false);
54:     await signOut();
55:     navigate("/login");
56:   };
57: 
58:   useEffect(() => {
59:     function handleClickOutside(event: MouseEvent) {
60:       if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
61:         setDropdownOpen(false);
62:       }
63:     }
64:     document.addEventListener("mousedown", handleClickOutside);
65:     return () => document.removeEventListener("mousedown", handleClickOutside);
66:   }, []);
67: 
68:   const userName = profile?.name || "Ridwan Setiawan";
69:   const schoolName = profile?.school || "SMA Sukahati Makasar";
70:   const avatar = profile?.avatar;
71: 
72:   // Highlights: Current day
73:   const today = new Date();
74:   const isCurrentMonth = today.getFullYear() === year && today.getMonth() === month;
75: 
76:   // Reminders list matching the Learnthru mockup style
77:   const [reminders, setReminders] = useState([
78:     { id: 1, title: "Input Nilai Harian Matematika", desc: "Batas Akhir: Jum'at, 19 Juni 2026", active: true },
79:     { id: 2, title: "Rapat Guru & Kurikulum", desc: "Senin, 22 Juni 2026 • 13:00 WIB", active: true },
80:     { id: 3, title: "Upload AI Modul RPP Semester", desc: "Kamis, 25 Juni 2026", active: false },
81:   ]);
82: 
83:   const toggleReminder = (id: number) => {
84:     setReminders(reminders.map(r => r.id === id ? { ...r, active: !r.active } : r));
85:   };
86: 
87:   return (
88:     <div className="w-[300px] p-6 flex flex-col gap-8 hidden xl:flex select-none shadow-none">
89:       
90:       {/* 1. Profile section at the top matching Stella Walton card */}
91:       <div className="flex flex-col items-center text-center relative py-4">
92:         <div className="relative w-28 h-28 rounded-full bg-white border border-slate-100 p-1 flex items-center justify-center mb-4 shadow-sm">
93:           <div className="w-full h-full rounded-full overflow-hidden bg-gradient-to-br from-[#DF7A5E] to-[#3C405B] shadow-inner">
94:             {avatar ? (
95:               <img src={avatar} alt={userName} className="w-full h-full object-cover" />
96:             ) : (
97:               <div className="w-full h-full flex items-center justify-center text-white font-bold text-2xl">
98:                 {userName.split(" ").map(n => n[0]).join("").substring(0, 2).toUpperCase()}
99:               </div>
100:             )}
101:           </div>
102:         </div>
103:         
104:         <h2 className="text-base font-extrabold text-slate-800 leading-tight mb-1">{userName}</h2>
105:         <p className="text-xs text-slate-400 font-extrabold uppercase tracking-wider mb-4">Guru</p>
106: 
107:         {/* Profile / Dropdown Action Button */}
108:         <div className="relative w-full px-8" ref={dropdownRef}>
109:           <button
110:             onClick={() => setDropdownOpen(!dropdownOpen)}
111:             className="w-full py-2 bg-[#3C405B]/10 hover:bg-[#3C405B]/15 rounded-full text-xs font-bold text-[#3C405B] border-0 cursor-pointer flex items-center justify-center gap-2 transition-all"
112:           >
113:             <Settings className="w-3.5 h-3.5" />
114:             Menu Akun
115:           </button>
116: 
117:           <AnimatePresence>
118:             {dropdownOpen && (
119:               <motion.div
120:                 initial={{ opacity: 0, y: 10, scale: 0.95 }}
121:                 animate={{ opacity: 1, y: 0, scale: 1 }}
122:                 exit={{ opacity: 0, y: 10, scale: 0.95 }}
123:                 transition={{ duration: 0.15 }}
124:                 className="absolute left-8 right-8 mt-2 bg-white rounded-[16px] shadow-lg border border-slate-100 py-1.5 z-50 overflow-hidden text-left"
125:               >
126:                 <div className="px-4 py-2 border-b border-gray-100">
127:                   <p className="text-xs font-bold text-gray-900 truncate">{userName}</p>
128:                   <p className="text-[10px] text-gray-500 truncate">{schoolName}</p>
129:                 </div>
130:                 
131:                 <Link
132:                   to="/settings"
133:                   onClick={() => setDropdownOpen(false)}
134:                   className="flex items-center gap-2.5 px-4 py-2.5 text-xs text-gray-700 hover:bg-gray-55 transition-colors"
135:                 >
136:                   <Settings className="w-3.5 h-3.5 text-gray-500" />
137:                   <span>Pengaturan Akun</span>
138:                 </Link>
139:                 
140:                 <div className="border-t border-gray-100 my-1"></div>
141:                 
142:                 <button
143:                   onClick={handleLogout}
144:                   className="w-full flex items-center gap-2.5 px-4 py-2.5 text-xs text-red-600 hover:bg-red-50 transition-colors text-left cursor-pointer border-0"
145:                 >
146:                   <LogOut className="w-3.5 h-3.5" />
147:                   <span>Logout</span>
148:                 </button>
149:               </motion.div>
150:             )}
151:           </AnimatePresence>
152:         </div>
153:       </div>
154: 
155:       {/* 2. Mini Calendar Widget matching December 2022 block */}
156:       <div className="flex flex-col gap-4">
157:         <div className="flex items-center justify-between px-1">
158:           <button 
159:             onClick={handlePrevMonth}
160:             className="w-7 h-7 rounded-full bg-slate-50 hover:bg-slate-100 flex items-center justify-center text-slate-500 border-0 cursor-pointer text-xs transition-colors"
161:           >
162:             <ChevronLeft className="w-3.5 h-3.5" />
163:           </button>
164:           <span className="text-xs font-extrabold text-slate-800 uppercase tracking-wider">
165:             {monthNames[month]} {year}
166:           </span>
167:           <button 
168:             onClick={handleNextMonth}
169:             className="w-7 h-7 rounded-full bg-slate-50 hover:bg-slate-100 flex items-center justify-center text-slate-500 border-0 cursor-pointer text-xs transition-colors"
170:           >
171:             <ChevronRight className="w-3.5 h-3.5" />
172:           </button>
173:         </div>
174: 
175:         {/* Days Header */}
176:         <div className="grid grid-cols-7 gap-1 text-center text-[10px] font-black text-slate-400">
177:           {daysOfWeek.map(day => (
178:             <div key={day}>{day}</div>
179:           ))}
180:         </div>
181: 
182:         {/* Calendar Grid Cells */}
183:         <div className="grid grid-cols-7 gap-y-2.5 gap-x-1 text-center text-xs">
184:           {calendarCells.map((day, idx) => {
185:             const isToday = isCurrentMonth && day === today.getDate();
186:             const isClassDay = day && (idx % 7 === 2 || idx % 7 === 4);
187: 
188:             return (
189:               <div key={idx} className="aspect-square flex items-center justify-center relative">
190:                 {day ? (
191:                   <button
192:                     className={`w-7 h-7 rounded-full text-xs font-extrabold transition-all border-0 flex items-center justify-center ${
193:                       isToday
194:                         ? "bg-[#DF7A5E] text-white shadow-sm"
195:                         : isClassDay
196:                         ? "bg-[#3C405B]/10 text-[#3C405B]"
197:                         : "text-slate-600 hover:bg-slate-50"
198:                     }`}
199:                   >
200:                     {day}
201:                   </button>
202:                 ) : (
203:                   <span />
204:                 )}
205:               </div>
206:             );
207:           })}
208:         </div>
209:       </div>
210: 
211:       {/* 3. Reminders list matching Reminders block */}
212:       <div className="flex flex-col gap-3">
213:         <h3 className="text-xs font-black text-slate-400 uppercase tracking-wider px-1">Reminders</h3>
214:         <div className="space-y-3">
215:           {reminders.map(item => (
216:             <div
217:               key={item.id}
218:               className="flex items-center gap-3.5 p-3.5 bg-white border border-slate-50 rounded-[20px] shadow-sm transition-all hover:shadow-md"
219:             >
220:               <button
221:                 onClick={() => toggleReminder(item.id)}
222:                 className={`w-10 h-10 rounded-[14px] flex items-center justify-center border transition-all duration-200 cursor-pointer ${
223:                   item.active 
224:                     ? "bg-[#3C405B] border-[#3C405B] text-white shadow-sm" 
225:                     : "bg-[#F4F6F9] border-slate-100 text-slate-400"
226:                 }`}
227:               >
228:                 <Bell className="w-4 h-4" />
229:               </button>
230:               <div className="flex-1 min-w-0">
231:                 <div className={`text-xs font-bold leading-snug truncate ${item.active ? "text-slate-700" : "text-slate-400 line-through"}`}>
232:                   {item.title}
233:                 </div>
234:                 <div className="text-[10px] text-slate-400 font-semibold mt-0.5">{item.desc}</div>
235:               </div>
236:             </div>
237:           ))}
238:         </div>
239:       </div>
240: 
241:     </div>
242:   );
243: }
